-- Capture the created reservation ids (adjust if your DB returns differently)
SET @res_horror  = (SELECT reservation_id FROM reservations WHERE customer_email = 'alice@example.com'  LIMIT 1);
SET @res_space1  = (SELECT reservation_id FROM reservations WHERE customer_email = 'bob@example.com'    LIMIT 1);
SET @res_space2  = (SELECT reservation_id FROM reservations WHERE customer_email = 'carol@example.com'  LIMIT 1);
SET @res_romcom  = (SELECT reservation_id FROM reservations WHERE customer_email = 'dave@example.com'   LIMIT 1);
SET @res_anim    = (SELECT reservation_id FROM reservations WHERE customer_email = 'eve@example.com'    LIMIT 1);

-- Find ticket ids to attach to reservations (one ticket per reservation as in your original)
SET @ticket_horror_1 = (SELECT movie_ticket_id FROM movie_tickets WHERE show_id = @show_horror LIMIT 1);
SET @ticket_space_1  = (SELECT movie_ticket_id FROM movie_tickets WHERE show_id = @show_space_1 LIMIT 1);
SET @ticket_space_2  = (SELECT movie_ticket_id FROM movie_tickets WHERE show_id = @show_space_2 LIMIT 1);
SET @ticket_romcom   = (SELECT movie_ticket_id FROM movie_tickets WHERE show_id = @show_romcom_future LIMIT 1);
SET @ticket_anim     = (SELECT movie_ticket_id FROM movie_tickets WHERE show_id = @show_anim LIMIT 1);

-- Update movie_tickets to reference reservations (set FK on many-side)
UPDATE movie_tickets SET reservation_id = @res_horror WHERE movie_ticket_id = @ticket_horror_1;
UPDATE movie_tickets SET reservation_id = @res_space1 WHERE movie_ticket_id = @ticket_space_1;
UPDATE movie_tickets SET reservation_id = @res_space2 WHERE movie_ticket_id = @ticket_space_2;
UPDATE movie_tickets SET reservation_id = @res_romcom WHERE movie_ticket_id = @ticket_romcom;
UPDATE movie_tickets SET reservation_id = @res_anim WHERE movie_ticket_id = @ticket_anim;

-- Adjust some seat_availability to RESERVED for seats that have tickets/reservations
UPDATE seats s
SET seat_availability = 'RESERVED'
WHERE s.seat_id IN (SELECT mt.seat_id FROM movie_tickets mt);